using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestDbContextFactory.Create();
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First(s => s.LastName == "Student");
            Assert.Equal("Test", retrieved.FirstMidName);
            Assert.Equal(new DateTime(2020, 9, 1), retrieved.EnrollmentDate);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = new DateTime(2000, 1, 1),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };

            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.First(i => i.LastName == "Instructor");
            Assert.Equal("Test", retrieved.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveDepartment()
        {
            var dept = new Department
            {
                Name = "Science",
                Budget = 250000,
                StartDate = new DateTime(2010, 9, 1)
            };

            _context.Departments.Add(dept);
            _context.SaveChanges();

            var retrieved = _context.Departments.First(d => d.Name == "Science");
            Assert.Equal(250000, retrieved.Budget);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            var dept = new Department { Name = "Math", Budget = 100000, StartDate = new DateTime(2010, 1, 1) };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 2001,
                Title = "Algebra",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            _context.Courses.Add(course);
            _context.SaveChanges();

            var retrieved = _context.Courses.First(c => c.CourseID == 2001);
            Assert.Equal("Algebra", retrieved.Title);
            Assert.Equal(3, retrieved.Credits);
        }

        [Fact]
        public void CanAddAndRetrieveEnrollment()
        {
            var student = new Student { FirstMidName = "A", LastName = "B", EnrollmentDate = DateTime.Now };
            _context.Students.Add(student);
            var dept = new Department { Name = "Dept", Budget = 100, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 3001, Title = "Course1", Credits = 2, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment { StudentID = student.ID, CourseID = course.CourseID, Grade = Grade.B };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var retrieved = _context.Enrollments.First(e => e.StudentID == student.ID);
            Assert.Equal(Grade.B, retrieved.Grade);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            var instructor = new Instructor { FirstMidName = "X", LastName = "Y", HireDate = DateTime.Now, CourseAssignments = new System.Collections.Generic.List<CourseAssignment>() };
            _context.Instructors.Add(instructor);
            var dept = new Department { Name = "D", Budget = 100, StartDate = DateTime.Now };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course { CourseID = 4001, Title = "C", Credits = 1, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var ca = new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID };
            _context.CourseAssignments.Add(ca);
            _context.SaveChanges();

            var retrieved = _context.CourseAssignments.Find(course.CourseID, instructor.ID);
            Assert.NotNull(retrieved);
        }

        [Fact]
        public void OfficeAssignment_HasInstructorIdAsKey()
        {
            var instructor = new Instructor { FirstMidName = "A", LastName = "B", HireDate = DateTime.Now, CourseAssignments = new System.Collections.Generic.List<CourseAssignment>() };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var oa = new OfficeAssignment { InstructorID = instructor.ID, Location = "Room 101" };
            _context.OfficeAssignments.Add(oa);
            _context.SaveChanges();

            var retrieved = _context.OfficeAssignments.Find(instructor.ID);
            Assert.NotNull(retrieved);
            Assert.Equal("Room 101", retrieved.Location);
        }

        [Fact]
        public void CanAddAndRetrieveNotification()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test message",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };

            _context.Notifications.Add(notification);
            _context.SaveChanges();

            var retrieved = _context.Notifications.First();
            Assert.Equal("Student", retrieved.EntityType);
            Assert.Equal("CREATE", retrieved.Operation);
        }

        [Fact]
        public void Person_FullName_ReturnsCorrectFormat()
        {
            var student = new Student { FirstMidName = "John", LastName = "Doe", EnrollmentDate = DateTime.Now };

            Assert.Equal("Doe, John", student.FullName);
        }

        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student { FirstMidName = "A", LastName = "B", EnrollmentDate = DateTime.Now };
            Assert.IsAssignableFrom<Person>(student);
        }

        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor { FirstMidName = "A", LastName = "B", HireDate = DateTime.Now };
            Assert.IsAssignableFrom<Person>(instructor);
        }

        public void Dispose()
        {
            _context?.Dispose();
        }
    }
}

