        {
            var studentId = _context.Students.First().ID;

            var result = _controller.Edit(studentId) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(studentId, model.ID);
        }

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = _context.Students.First();
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var editedStudent = new Student
            {
                ID = student.ID,
                FirstMidName = "Updated",
                LastName = student.LastName,
                EnrollmentDate = student.EnrollmentDate
            };

            var result = _controller.Edit(editedStudent) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidDate_ReturnsView()
        {
            var student = _context.Students.First();
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var editedStudent = new Student
            {
                ID = student.ID,
                FirstMidName = student.FirstMidName,
                LastName = student.LastName,
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(editedStudent) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenStudentNotFound()
        {
            var result = _controller.Delete(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsViewResult_WithStudent()
        {
            var studentId = _context.Students.First().ID;

            var result = _controller.Delete(studentId) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(studentId, model.ID);
        }

        [Fact]
        public void DeleteConfirmed_RemovesStudent_AndRedirects()
        {
            var studentId = _context.Students.First().ID;

            var result = _controller.DeleteConfirmed(studentId) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, _context.Students.Count());
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }
    }
}

