using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            SeedData();
            _controller = new InstructorsController(_context);
        }

        private void SeedData()
        {
            var dept = new Department { Name = "Engineering", Budget = 350000, StartDate = new DateTime(2007, 9, 1) };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var instructor1 = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = new DateTime(1995, 3, 11),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
            };
            var instructor2 = new Instructor
            {
                FirstMidName = "Fadi",
                LastName = "Fakhouri",
                HireDate = new DateTime(2002, 7, 6),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.AddRange(instructor1, instructor2);
            _context.SaveChanges();

            var course = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID };
            _context.Courses.Add(course);
            _context.SaveChanges();

            _context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = instructor1.ID,
                CourseID = course.CourseID
            });
            _context.SaveChanges();
        }

        [Fact]
        public void Index_ReturnsViewResult_WithInstructorIndexData()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<ContosoUniversity.Models.SchoolViewModels.InstructorIndexData>(result.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var instructorId = _context.Instructors.First(i => i.LastName == "Abercrombie").ID;

            var result = _controller.Index(instructorId, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<ContosoUniversity.Models.SchoolViewModels.InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Index_WithCourseId_PopulatesEnrollments()
        {
            var instructorId = _context.Instructors.First(i => i.LastName == "Abercrombie").ID;

            var student = new Student { FirstMidName = "Test", LastName = "Student", EnrollmentDate = DateTime.Now };
            _context.Students.Add(student);
            _context.SaveChanges();
            _context.Enrollments.Add(new Enrollment { StudentID = student.ID, CourseID = 1050, Grade = Grade.A });
            _context.SaveChanges();

            var result = _controller.Index(instructorId, 1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<ContosoUniversity.Models.SchoolViewModels.InstructorIndexData>(result.Model);
            Assert.NotNull(model.Enrollments);
            Assert.Single(model.Enrollments);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenInstructorNotFound()
        {
            var result = _controller.Details(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithInstructor()
        {
            var instructorId = _context.Instructors.First().ID;

            var result = _controller.Details(instructorId) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructorId, model.ID);
        }

        [Fact]
        public void Create_Get_ReturnsViewResult_WithInstructor()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
        }

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Roger",
                LastName = "Harui",
                HireDate = new DateTime(1998, 7, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(3, _context.Instructors.Count());
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AssignsCourses()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2000, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, new[] { "1050" }) as RedirectToActionResult;

            Assert.NotNull(result);
            var created = _context.Instructors.First(i => i.LastName == "Instructor");
            Assert.Single(_context.CourseAssignments.Where(ca => ca.InstructorID == created.ID));
        }

        [Fact]
        public void Create_Post_InvalidModel_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = new DateTime(2000, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsViewResult_WithInstructor()
        {
            var instructorId = _context.Instructors.First().ID;

            var result = _controller.Edit(instructorId) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructorId, model.ID);
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenInstructorNotFound()
        {
            var result = _controller.Delete(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsViewResult_WithInstructor()
        {
            var instructorId = _context.Instructors.First().ID;

            var result = _controller.Delete(instructorId) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructorId, model.ID);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructor_AndRedirects()
        {
            var instructor = _context.Instructors.First(i => i.LastName == "Fakhouri");

            var result = _controller.DeleteConfirmed(instructor.ID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(_context.Instructors);
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            var instructor = _context.Instructors.First(i => i.LastName == "Abercrombie");
            var dept = _context.Departments.First();
            dept.InstructorID = instructor.ID;
            _context.SaveChanges();

            _controller.DeleteConfirmed(instructor.ID);

            var updatedDept = _context.Departments.First();
            Assert.Null(updatedDept.InstructorID);
        }

        public void Dispose()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }
    }
}

