using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class DbInitializerTests : IDisposable
    {
        private readonly SchoolContext _context;

        public DbInitializerTests()
        {
            _context = TestDbContextFactory.Create();
        }

        [Fact]
        public void Initialize_SeedsStudents()
        {
            DbInitializer.Initialize(_context);

            Assert.Equal(8, _context.Students.Count());
        }

        [Fact]
        public void Initialize_SeedsInstructors()
        {
            DbInitializer.Initialize(_context);

            Assert.Equal(5, _context.Instructors.Count());
        }

        [Fact]
        public void Initialize_SeedsDepartments()
        {
            DbInitializer.Initialize(_context);

            Assert.Equal(4, _context.Departments.Count());
        }

        [Fact]
        public void Initialize_SeedsCourses()
        {
            DbInitializer.Initialize(_context);

            Assert.Equal(7, _context.Courses.Count());
        }

        [Fact]
        public void Initialize_SeedsEnrollments()
        {
            DbInitializer.Initialize(_context);

            Assert.Equal(11, _context.Enrollments.Count());
        }

        [Fact]
        public void Initialize_SeedsOfficeAssignments()
        {
            DbInitializer.Initialize(_context);

            Assert.Equal(3, _context.OfficeAssignments.Count());
        }

        [Fact]
        public void Initialize_SeedsCourseAssignments()
        {
            DbInitializer.Initialize(_context);

            Assert.Equal(8, _context.CourseAssignments.Count());
        }

        [Fact]
        public void Initialize_DoesNotReseed_WhenDataExists()
        {
            DbInitializer.Initialize(_context);
            var studentCount = _context.Students.Count();

            DbInitializer.Initialize(_context);

            Assert.Equal(studentCount, _context.Students.Count());
        }

        [Fact]
        public void Initialize_StudentHasCorrectData()
        {
            DbInitializer.Initialize(_context);

            var student = _context.Students.First(s => s.LastName == "Alexander");
            Assert.Equal("Carson", student.FirstMidName);
            Assert.Equal(new DateTime(2010, 9, 1), student.EnrollmentDate);
        }

        [Fact]
        public void Initialize_DepartmentHasAdministrator()
        {
            DbInitializer.Initialize(_context);

            var dept = _context.Departments.First(d => d.Name == "English");
            Assert.NotNull(dept.InstructorID);
        }

        public void Dispose()
        {
            _context?.Dispose();
        }
    }
}

